export interface ReplBridge {
  call<T = unknown>(method: string, params?: unknown): Promise<T>;
  on(event: string, handler: (...args: any[]) => void): void;
  off(event: string, handler: (...args: any[]) => void): void;
  emit(event: string, ...args: any[]): void;
}

export function createReplBridge(transport: Transport): ReplBridge {
  return {
    call: (method, params) => transport.request(method, params),
    on: (event, handler) => transport.on(event, handler),
    off: (event, handler) => transport.off(event, handler),
    emit: (event, ...args) => transport.emit(event, ...args)
  };
}

export class DirectConnectManager {
  private sessions = new Map<string, DirectConnectSession>();

  async createSession(options: CreateSessionOptions): Promise<SessionInfo> {
    const sessionId = generateSessionId();
    const token = await generateAuthToken(sessionId);

    const session: DirectConnectSession = {
      id: sessionId,
      token,
      createdAt: Date.now(),
      status: 'active',
      permissions: options.permissions
    };

    this.sessions.set(sessionId, session);
    return { sessionId, token, connectUrl: buildConnectUrl(sessionId, token) };
  }

  getSession(sessionId: string): DirectConnectSession | undefined {
    return this.sessions.get(sessionId);
  }
}

export class SessionsWebSocket {
  private ws: WebSocket;
  private messageQueue: Message[] = [];

  constructor(private sessionId: string, private authToken: string) {
    this.ws = new WebSocket(`wss://remote.example.com/sessions/${sessionId}`, {
      headers: { 'Authorization': `Bearer ${authToken}` }
    });

    this.ws.onmessage = (event) => {
      const message = JSON.parse(event.data);
      this.handleMessage(message);
    };
  }

  sendMessage(type: string, data: any): void {
    if (this.ws.readyState === WebSocket.OPEN) {
      this.ws.send(JSON.stringify({ type, data }));
    } else {
      this.messageQueue.push({ type, data });
    }
  }
}

export async function handleOAuthCallback(
  code: string, 
  state: string
): Promise<OAuthProfile> {
  // 验证 state 防止 CSRF 攻击
  if (!isValidState(state)) {
    throw new Error('Invalid state parameter');
  }

  // 交换 code 获取 access token
  const tokens = await exchangeCodeForTokens(code);

  // 获取用户信息
  const profile = await getUserProfile(tokens.accessToken);

  // 创建或更新本地用户记录
  await upsertUser(profile);

  return profile;
}

